SELECT d.*,
       ic.channel_name AS inviter_channel_name_join,
       ec.channel_name AS invitee_channel_name_join
  FROM jst_channel_distribution_ledger d
  LEFT JOIN jst_channel ic ON d.inviter_channel_id = ic.channel_id AND ic.del_flag = '0'
  LEFT JOIN jst_channel ec ON d.invitee_channel_id = ec.channel_id AND ec.del_flag = '0'

    AND d.inviter_channel_id = #{inviterChannelId}
    AND d.invitee_channel_id = #{inviteeChannelId}
    AND d.status = #{status}

ORDER BY d.create_time DESC

