inviter_channel_id = #{inviterChannelId}, invitee_channel_id = #{inviteeChannelId}, order_id = #{orderId}, order_no = #{orderNo}, base_amount = #{baseAmount}, applied_rate = #{appliedRate}, raw_amount = #{rawAmount}, compress_ratio = #{compressRatio}, amount = #{amount}, status = #{status}, accrue_at = #{accrueAt}, accrued_at = #{accruedAt}, update_time = NOW()
WHERE ledger_id = #{ledgerId}

